function latestUserText() {
  const msgs = board.channel(board.MAIN_CHANNEL) || [];
  for (let i = msgs.length - 1; i >= 0; i--) {
    const msg = msgs[i] || {};
    if (msg.role !== "user") continue;
    if (typeof msg.content === "string" && msg.content.trim()) return msg.content.trim();
    const parts = Array.isArray(msg.parts) ? msg.parts : [];
    const text = parts.map(function(part) {
      return part && part.type === "text" && typeof part.text === "string" ? part.text : "";
    }).join("").trim();
    if (text) return text;
  }
  return "";
}

const checkpoints = ["tang", "song", "yuan", "ming"];
const checkpointInfo = {
  tang: { title: "唐朝月门", badge: "badge_tang_moon", badge_label: "唐月徽章", dynasty: "唐朝", points: 100, hint: "这一关要一句带月亮意象的唐诗，可以想《静夜思》或《关山月》。" },
  song: { title: "宋朝江门", badge: "badge_song_river", badge_label: "宋河徽章", dynasty: "宋朝", points: 100, hint: "这一关要一句宋代诗词里写江河、湖水或浪涛的句子，可以想苏轼和赤壁江水。" },
  yuan: { title: "元曲暮门", badge: "badge_yuan_dusk", badge_label: "元暮徽章", dynasty: "元朝", points: 100, hint: "这一关要一句《天净沙·秋思》里的句子，可以想枯藤、小桥、古道这些画面。" },
  ming: { title: "明朝青石门", badge: "badge_ming_courage", badge_label: "明勇徽章", dynasty: "明朝", points: 100, hint: "这一关要一句于谦《石灰吟》里的句子，可以想千锤万凿、粉骨碎身、清白这些词。" }
};
const existing = board.getVar("poetry_journey_state") || {};
const state = Object.assign({
  checkpoint: "tang",
  status: "playing",
  score: 0,
  badges: [],
  attempts: {},
  awaiting_response: false,
  last_result: "",
  last_line: "",
  last_badge: "",
  last_badge_label: "",
  last_dynasty: "",
  last_points: 0
}, existing || {});
state.badges = Array.isArray(state.badges) ? state.badges : [];
state.attempts = state.attempts && typeof state.attempts === "object" ? state.attempts : {};
if (checkpoints.indexOf(state.checkpoint) < 0 && state.status !== "finished") {
  state.checkpoint = "tang";
}
state.latest_user_text = latestUserText();
state.current_info = checkpointInfo[state.checkpoint] || checkpointInfo.tang;
state.checkpoints = checkpoints;
const idx = checkpoints.indexOf(state.checkpoint);
const nextCheckpoint = idx >= 0 && idx < checkpoints.length - 1 ? checkpoints[idx + 1] : "";
const nextInfo = nextCheckpoint ? checkpointInfo[nextCheckpoint] : null;
board.setVar("poetry_journey_state", state);
board.setVar("poetry_journey_state_text", JSON.stringify(state, null, 2));
board.setVar("current_checkpoint", state.checkpoint);
board.setVar("current_dynasty", state.current_info.dynasty);
board.setVar("current_badge", state.current_info.badge);
board.setVar("current_badge_label", state.current_info.badge_label);
board.setVar("current_points", state.current_info.points);
board.setVar("current_hint", state.current_info.hint || "");
board.setVar("next_dynasty", nextInfo ? nextInfo.dynasty : "终点");
board.setVar("current_score", state.score || 0);
board.setVar("badge_list", state.badges.join(","));
const badgeLabels = {
  badge_tang_moon: "唐月徽章",
  badge_song_river: "宋河徽章",
  badge_yuan_dusk: "元暮徽章",
  badge_ming_courage: "明勇徽章"
};
board.setVar("badge_label_list", state.badges.map(function(badge) {
  return badgeLabels[badge] || badge;
}).join("、"));
board.setVar("latest_user_text", state.latest_user_text);
board.setVar("challenge_judgement_text", "");
board.setChannel("poetry_input_channel", [{
  role: "user",
  parts: [{ type: "text", text: state.latest_user_text || "开始" }]
}]);
board.setChannel("poetry_response_channel", [{
  role: "user",
  parts: [{ type: "text", text: state.latest_user_text || "开始" }]
}]);

const state = board.getVar("poetry_journey_state") || {};
function containsAny(text, arr) {
  for (let i = 0; i < arr.length; i++) {
    if (text.indexOf(arr[i]) >= 0) return true;
  }
  return false;
}
const accepted = {
  tang: ["床前明月光", "举头望明月", "明月出天山", "我寄愁心与明月"],
  song: ["大江东去浪淘尽", "水光潋滟晴方好", "竹外桃花三两枝"],
  yuan: ["枯藤老树昏鸦", "小桥流水人家", "古道西风瘦马", "夕阳西下"],
  ming: ["千锤万凿出深山", "粉骨碎身浑不怕", "要留清白在人间"]
};
const latest = String(state.latest_user_text || "");
const cp = String(state.checkpoint || "tang");
if (state.status === "finished") {
  board.setVar("poetry_route", "finished_roleplay_chat");
} else if (state.awaiting_response === true) {
  board.setVar("poetry_route", "judge_challenge");
} else if (containsAny(latest, accepted[cp] || [])) {
  state.awaiting_response = true;
  board.setVar("poetry_journey_state", state);
  board.setVar("poetry_journey_state_text", JSON.stringify(state, null, 2));
  board.setVar("poetry_route", "judge_challenge");
} else {
  state.awaiting_response = true;
  board.setVar("poetry_journey_state", state);
  board.setVar("poetry_journey_state_text", JSON.stringify(state, null, 2));
  board.setVar("poetry_route", cp + "_checkpoint");
}

function containsAny(text, arr) {
  for (let i = 0; i < arr.length; i++) {
    if (text.indexOf(arr[i]) >= 0) return arr[i];
  }
  return "";
}
function addUnique(arr, item) {
  if (arr.indexOf(item) < 0) arr.push(item);
}
const accepted = {
  tang: ["床前明月光", "举头望明月", "明月出天山", "我寄愁心与明月"],
  song: ["大江东去浪淘尽", "水光潋滟晴方好", "竹外桃花三两枝"],
  yuan: ["枯藤老树昏鸦", "小桥流水人家", "古道西风瘦马", "夕阳西下"],
  ming: ["千锤万凿出深山", "粉骨碎身浑不怕", "要留清白在人间"]
};
const info = {
  tang: { dynasty: "唐朝", badge: "badge_tang_moon", badge_label: "唐月徽章", points: 100 },
  song: { dynasty: "宋朝", badge: "badge_song_river", badge_label: "宋河徽章", points: 100 },
  yuan: { dynasty: "元朝", badge: "badge_yuan_dusk", badge_label: "元暮徽章", points: 100 },
  ming: { dynasty: "明朝", badge: "badge_ming_courage", badge_label: "明勇徽章", points: 100 }
};
const state = board.getVar("poetry_journey_state") || {};
state.badges = Array.isArray(state.badges) ? state.badges : [];
state.attempts = state.attempts && typeof state.attempts === "object" ? state.attempts : {};
const cp = String(state.checkpoint || "tang");
const latest = String(state.latest_user_text || board.getVar("latest_user_text") || "");
const line = containsAny(latest, accepted[cp] || []);
const judgeText = String(board.getVar("challenge_judgement_text") || "");
const modelPassed = /passed\s*=\s*true/i.test(judgeText) && !/passed\s*=\s*false/i.test(judgeText);
const passed = !!line || modelPassed;
state.attempts[cp] = (Number(state.attempts[cp]) || 0) + 1;
state.last_line = line || latest;
state.last_result = passed ? "passed" : "retry";
state.last_reason = passed ? "cleared checkpoint" : "needs another poem line";
if (passed) {
  const current = info[cp] || info.tang;
  state.awaiting_response = false;
  state.last_badge = current.badge;
  state.last_badge_label = current.badge_label;
  state.last_dynasty = current.dynasty;
  state.last_points = current.points;
  const nextBadges = Array.isArray(state.badges) ? state.badges.slice() : [];
  addUnique(nextBadges, current.badge);
  state.badges = nextBadges;
  board.setVar("poetry_award_route", cp + "_award_badge");
  board.setVar("poetry_result_route", "checkpoint_clear");
} else {
  state.awaiting_response = true;
  state.last_badge = "";
  state.last_badge_label = "";
  state.last_dynasty = info[cp] ? info[cp].dynasty : "";
  state.last_points = 0;
  board.setVar("poetry_award_route", "");
  board.setVar("poetry_result_route", "retry_hint");
}
board.setVar("poetry_journey_state", state);
board.setVar("poetry_journey_state_text", JSON.stringify(state, null, 2));
board.setVar("last_badge", state.last_badge || "");
board.setVar("last_badge_label", state.last_badge_label || "");
board.setVar("last_dynasty", state.last_dynasty || "");
board.setVar("last_points", state.last_points || 0);
board.setVar("last_line", state.last_line || "");
const responseText = passed ?
  ("孩子说出了：" + (state.last_line || latest) + "。他通过了" + (state.last_dynasty || "") + "关卡，请庆祝通关。") :
  ("孩子刚才说：" + latest + "。这次还没有通过" + (state.last_dynasty || "") + "关卡，请给一个提示。");
board.setChannel("poetry_response_channel", [{
  role: "user",
  parts: [{ type: "text", text: responseText }]
}]);

const order = ["tang", "song", "yuan", "ming"];
const state = board.getVar("poetry_journey_state") || {};
const idx = order.indexOf(String(state.checkpoint || "tang"));
if (idx >= 0 && idx < order.length - 1) {
  state.checkpoint = order[idx + 1];
  state.status = "playing";
  state.awaiting_response = false;
  board.setVar("poetry_after_award_route", "audit");
} else {
  state.status = "finished";
  state.checkpoint = "finished";
  state.awaiting_response = false;
  board.setVar("poetry_after_award_route", "journey_finish");
}
state.score = (Number(state.score) || 0) + (Number(state.last_points) || 0);
board.setVar("poetry_journey_state", state);
board.setVar("poetry_journey_state_text", JSON.stringify(state, null, 2));
board.setVar("current_score", state.score || 0);
board.setVar("badge_list", Array.isArray(state.badges) ? state.badges.join(",") : "");
const badgeLabels = {
  badge_tang_moon: "唐月徽章",
  badge_song_river: "宋河徽章",
  badge_yuan_dusk: "元暮徽章",
  badge_ming_courage: "明勇徽章"
};
board.setVar("badge_label_list", Array.isArray(state.badges) ? state.badges.map(function(badge) {
  return badgeLabels[badge] || badge;
}).join("、") : "");
board.setChannel("poetry_response_channel", [{
  role: "user",
  parts: [{ type: "text", text: "孩子已经收集完全部朝代徽章，请为古诗旅行收束。" }]
}]);

const state = board.getVar("poetry_journey_state") || {};
const badges = Array.isArray(state.badges) ? state.badges : [];
const attempts = state.attempts && typeof state.attempts === "object" ? state.attempts : {};
board.setVar("tmp_checkpoint_progress_line",
  "checkpoint_progress: status=" + (state.status || "playing") +
  "; checkpoint=" + (state.checkpoint || "") +
  "; score=" + (state.score || 0) +
  "; badges=" + badges.join(",") +
  "; awaiting=" + (state.awaiting_response === true));
board.setVar("tmp_achievement_log_line",
  "achievement_log: checkpoint=" + (state.last_dynasty || state.checkpoint || "") +
  "; result=" + (state.last_result || "") +
  "; line=" + (state.last_line || "") +
  "; attempts=" + JSON.stringify(attempts));
board.setVar("tmp_badge_events_line",
  "badge_events: badge=" + (state.last_badge || "none") +
  "; points=" + (state.last_points || 0) +
  "; score=" + (state.score || 0));
